from base64 import b64decode
from unittest import TestCase
from starkbank import iso8583
from starkbank.iso8583.template.visa import visa


iso8583.encoding = "ascii"


class TestIsoMessage(TestCase):

    def testParseUnparseMastercardAuthorization(self):
        raw64 = ""
        raw = b64decode(raw64)[2:]
        msg = iso8583.parse(raw)
        self.assertEqual(raw, iso8583.unparse(msg))

    def testParseUnparseMastercardClearing(self):
        raw64 = ""
        raw = b64decode(raw64)[2:]
        msg = iso8583.parse(raw)
        self.assertEqual(raw, iso8583.unparse(msg))

    def testParseUnparseVisaAuthorization(self):
        # raw64 = ""
        # raw64 = "ANAAABYBAgDQAAAAAAAAAAAAAAAAAAAAAAABAHI8ZIEo4IA2EEEjcJmZAAApAAAAAAAAAEEACBYYVlAAABcVVlAIFjESWZkHcpEgAAsBI0VniQElBBI3CZmQAAKdMRIgESEhIFMRJ/Py8vjx+PDw8PDx9/Zg8UBAQEBAw8HZxEDBw8PF1+PW2UBAwcPY5MnZxdlA1cHUxUBAQEBAQEBAQEBAQMPJ4+hA1cHUxUBAQEDk4ghACvD28PDw+fTw9PQECAAAQAmAAAAAAAAAAOgFgAAAAAI="
        raw64 = ""
        raw = b64decode(raw64)[2:]
        msg = iso8583.parse(raw, template=visa)
        self.assertEqual(raw, iso8583.unparse(msg, template=visa))
